"""Unit tests for notifyError toolkit."""

from __future__ import annotations

import json

import pytest

from agno_platform.agents.notify.tools import notify_error


@pytest.mark.asyncio
async def test_notify_error_without_telegram(monkeypatch: pytest.MonkeyPatch) -> None:
    monkeypatch.setattr(
        "agno_platform.agents.notify.tools._module_level_send", lambda *_a, **_k: None
    )
    assert await notify_error.entrypoint(reason="unmapped") == "error_notified"  # type: ignore[misc]


@pytest.mark.asyncio
async def test_notify_error_telegram_success(monkeypatch: pytest.MonkeyPatch) -> None:
    monkeypatch.setattr(
        "agno_platform.agents.notify.tools._module_level_send",
        lambda _reason, _user_message_excerpt="": json.dumps({"status": "success", "message_id": 1}),
    )
    assert (
        await notify_error.entrypoint(reason="fail", user_message_excerpt="hi")  # type: ignore[misc]
        == "error_notified"
    )


@pytest.mark.asyncio
async def test_notify_error_telegram_failure_still_acks(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    monkeypatch.setattr(
        "agno_platform.agents.notify.tools._module_level_send",
        lambda _reason, _user_message_excerpt="": json.dumps(
            {"status": "error", "message": "chat not found"}
        ),
    )
    assert await notify_error.entrypoint(reason="fail") == "error_notified"  # type: ignore[misc]


@pytest.mark.asyncio
async def test_notify_error_telegram_exception_still_acks(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    def _raise(*_a: object, **_k: object) -> None:
        raise ConnectionError("telegram unreachable")

    monkeypatch.setattr("agno_platform.agents.notify.tools._module_level_send", _raise)
    assert await notify_error.entrypoint(reason="fail") == "error_notified"  # type: ignore[misc]

